// ─── TYPES ───────────────────────────────────────────────────────────────────

interface ProcessStep {
  id: string;
  name: string;
  short: string;
  temp: number | null;
  time: number;
  color: number;
  type: string;
  x: number;
  z: number;
}

interface RobotObject {
  group: THREE.Group;
  turret: THREE.Group;
  shoulder: THREE.Group;
  upperArm: THREE.Group;
  elbow: THREE.Group;
  foreArm: THREE.Group;
  wrist: THREE.Group;
  gripper: THREE.Group;
  statusPL: THREE.PointLight;
  basePos: THREE.Vector3;
  runIK: (tgt: THREE.Vector3) => void;
  getJoints: () => JointData;
  worldPos: () => THREE.Vector3;
}

interface JointData {
  base: { c: number };
  shoulder: { c: number };
  elbow: { c: number };
  wrist: { c: number };
}

interface WaferUIState {
  wi: number;
  name: string;
  state: string;
  stepIdx: number;
  stepName: string;
  processTimer: number;
  stepTime: number;
  done: boolean;
  launched: boolean;
}

interface UIState {
  wafers: WaferUIState[];
  simTime: number;
  fps: number;
  active: number;
  completed: number;
  jointsA: JointData | null;
  jointsEFEM: JointData | null;
  jointsC: JointData | null;
}

interface LogEntry {
  id: number;
  msg: string;
  cls: "pick" | "place" | "move" | "";
}

interface TooltipState {
  visible: boolean;
  x: number;
  y: number;
  name: string;
  temp: string;
  meta: string;
  tempColor: string;
}

interface CameraPreset {
  theta: number;
  phi: number;
  radius: number;
  cx: number;
  cy: number;
  cz: number;
}

